    delay?: number
    backoff?: number
  } = {},
): Promise<T> {
  const { maxAttempts = 3, delay = 1000, backoff = 2 } = options
  let lastError: Error | undefined
  let currentDelay = delay

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await fn()
    } catch (e) {
      lastError = e as Error
      if (attempt < maxAttempts) {
