  }, indent)
}

export function hashCode(str: string): number {
  let hash = 0
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i)
    hash = (hash << 5) - hash + char
    hash = hash & hash
  }
  return hash
}

export function generateId(prefix = ''): string {
  return `${prefix}${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`
}

export function randomString(length: number): string {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'
  let result = ''
  for (let i = 0; i < length; i++) {
    result += chars[Math.floor(Math.random() * chars.length)]
  }
  return result
}

export function escapeHtml(str: string): string {
  const escapeMap: Record<string, string> = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#39;',
  }
  return str.replace(/[&<>"']/g, char => escapeMap[char])
}

export function unescapeHtml(str: string): string {
  const unescapeMap: Record<string, string> = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
  }
  return str.replace(/&amp;|&lt;|&gt;|&quot;|&#39;/g, entity => unescapeMap[entity])
}

export function escapeRegex(str: string): string {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
}

export function escapeShell(str: string): string {
  return str.replace(/'/g, "'\\''")
}

export function parseQuery(queryString: string): Record<string, string> {
  const params: Record<string, string> = {}
  for (const pair of queryString.split('&')) {
    const [key, value] = pair.split('=')
    if (key) {
      params[decodeURIComponent(key)] = decodeURIComponent(value || '')
    }
  }
  return params
}

export function buildQuery(params: Record<string, string>): string {
  return Object.entries(params)
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
    .join('&')
}

export function isValidEmail(email: string): boolean {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
  return emailRegex.test(email)
}

export function isValidUrl(url: string): boolean {
  try {
    new URL(url)
    return true
  } catch {
    return false
  }
}

export function uniqBy<T, K>(
  array: T[],
  keyFn: (item: T) => K,
): T[] {
  const seen = new Set<K>()
  return array.filter(item => {
    const key = keyFn(item)
    if (seen.has(key)) return false
    seen.add(key)
    return true
  })
}

export function difference<T>(a: T[], b: T[]): T[] {
  const bSet = new Set(b)
  return a.filter(item => !bSet.has(item))
}

export function intersection<T>(a: T[], b: T[]): T[] {
  const bSet = new Set(b)
  return a.filter(item => bSet.has(item))
}

export function union<T>(a: T[], b: T[]): T[] {
  return [...new Set([...a, ...b])]
}

export function last<T>(array: T[]): T | undefined {
  return array[array.length - 1]
}

export function first<T>(array: T[]): T | undefined {
  return array[0]
}

export function isEmpty(value: any): boolean {
  if (value == null) return true
  if (typeof value === 'string' || Array.isArray(value)) return value.length === 0
  if (typeof value === 'object') return Object.keys(value).length === 0
  return false
}

export function isEqual(a: any, b: any): boolean {
  if (a === b) return true
  if (a == null || b == null) return false
  if (typeof a !== typeof b) return false
  if (typeof a !== 'object') return false
  if (Array.isArray(a) !== Array.isArray(b)) return false
  const keysA = Object.keys(a)
  const keysB = Object.keys(b)
  if (keysA.length !== keysB.length) return false
  return keysA.every(key => isEqual(a[key], b[key]))
}

export function pickRandom<T>(array: T[]): T {
  return array[Math.floor(Math.random() * array.length)]
}

export function sortNumbers(array: number[]): number[] {
  return [...array].sort((a, b) => a - b)
}

export function sum(numbers: number[]): number {
  return numbers.reduce((a, b) => a + b, 0)
}

export function average(numbers: number[]): number {
  return numbers.length > 0 ? sum(numbers) / numbers.length : 0
}

export function median(numbers: number[]): number {
  const sorted = sortNumbers(numbers)
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 !== 0
    ? sorted[mid]
    : (sorted[mid - 1]! + sorted[mid]!) / 2
}

export function min(numbers: number[]): number | undefined {
  return numbers.length > 0 ? Math.min(...numbers) : undefined
}

export function max(numbers: number[]): number | undefined {
  return numbers.length > 0 ? Math.max(...numbers) : undefined
}

export function clamp(n: number, min: number, max: number): number {
  return Math.min(Math.max(n, min), max)
}

export function inRange(n: number, min: number, max: number): boolean {
  return n >= min && n <= max
}

export function roundTo(n: number, decimals: number): number {
  const factor = Math.pow(10, decimals)
  return Math.round(n * factor) / factor
}

export function padStart(str: string, length: number, char = ' '): string {
  return str.padStart(length, char)
}

export function padEnd(str: string, length: number, char = ' '): string {
  return str.padEnd(length, char)
}

export function reverseString(str: string): string {
  return str.split('').reverse().join('')
}

export function words(str: string): string[] {
  return str.trim().split(/\s+/)
}

export function unwords(words: string[]): string {
  return words.join(' ')
}

export function lines(str: string): string[] {
  return str.split('\n')
}

export function unlines(lines: string[]): string {
  return lines.join('\n')
}

export function repeat(str: string, count: number): string {
  return str.repeat(count)
}

export function leftPad(str: string, length: number, char = ' '): string {
  return repeat(char, length - str.length) + str
}

export function rightPad(str: string, length: number, char = ' '): string {
  return str + repeat(char, length - str.length)
}

export function stripPrefix(str: string, prefix: string): string {
  return str.startsWith(prefix) ? str.slice(prefix.length) : str
}

export function stripSuffix(str: string, suffix: string): string {
  return str.endsWith(suffix) ? str.slice(0, -suffix.length) : str
}

export function includes<T>(array: T[], item: T): boolean {
  return array.includes(item)
}

export function findIndex<T>(
  array: T[],
  predicate: (item: T) => boolean,
): number {
  return array.findIndex(predicate)
}

export function findLastIndex<T>(
  array: T[],
  predicate: (item: T) => boolean,
): number {
  return array.findLastIndex(predicate)
}

export function findLast<T>(
  array: T[],
  predicate: (item: T) => boolean,
): T | undefined {
  return array.findLast(predicate)
}

export function drop<T>(array: T[], n: number): T[] {
  return array.slice(n)
}

export function take<T>(array: T[], n: number): T[] {
  return array.slice(0, n)
}

export function dropLast<T>(array: T[], n: number): T[] {
  return array.slice(0, -n)
}

export function takeLast<T>(array: T[], n: number): T[] {
  return array.slice(-n)
}

export function dropWhile<T>(
  array: T[],
  predicate: (item: T) => boolean,
): T[] {
  let i = 0
  while (i < array.length && predicate(array[i]!)) i++
  return array.slice(i)
}

export function takeWhile<T>(
  array: T[],
  predicate: (item: T) => boolean,
): T[] {
  const result: T[] = []
  for (const item of array) {
    if (!predicate(item)) break
    result.push(item)
  }
  return result
}

export function zipWith<T, U, V>(
  a: T[],
  b: U[],
  fn: (a: T, b: U) => V,
): V[] {
  const result: V[] = []
  const len = Math.min(a.length, b.length)
  for (let i = 0; i < len; i++) {
    result.push(fn(a[i]!, b[i]!))
  }
  return result
}

export function/ap<T>(fns: Array<() => T>): T[] {
  return fns.map(fn => fn())
}

export function curry<T, R>(
  fn: (a: T) => R,
): (a: T) => R {
  return fn
}

export function compose<T>(
  ...fns: Array<(a: any) => any>
): (a: any) => T {
  return (a: any) => fns.reduceRight((v, f) => f(v), a)
}

export function pipe<T>(
  ...fns: Array<(a: any) => any>
): (a: any) => T {
  return (a: any) => fns.reduce((v, f) => f(v), a)
}

export function identity<T>(x: T): T {
  return x
}

export function constant<T>(x: T): () => T {
  return () => x
}

export function always<T>(x: T): () => T {
  return () => x
}

export function tap<T>(fn: (x: T) => void): (x: T) => T {
  return (x: T) => {
    fn(x)
    return x
  }
}

export function flip<T, U, V>(fn: (a: T, b: U) => V): (b: U, a: T) => V {
  return (b, a) => fn(a, b)
}

export function negate<T>(pred: (x: T) => boolean): (x: T) => boolean {
  return x => !pred(x)
}

export function juxt<T, R>(
  ...fns: Array<(a: T) => R>
): (a: T) => R[] {
  return (a: T) => fns.map(fn => fn(a))
}

export function converge<T, U>(
  convergingFn: (values: any[]) => T,
  ...fns: Array<(a: U) => any>
): (a: U) => T {
  return (a: U) => convergingFn(fns.map(fn => fn(a)))
}

export function prop<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key]
}

export function props<T, K extends keyof T>(obj: T, keys: K[]): T[K][] {
  return keys.map(key => obj[key])
}

export function assoc<T, K extends string, V>(
  obj: T,
  key: K,
  value: V,
): T & Record<K, V> {
  return { ...obj, [key]: value } as T & Record<K, V>
}

export function dissoc<T, K extends keyof T>(
  obj: T,
  key: K,
): Omit<T, K> {
  const { [key]: _, ...rest } = obj as any
  return rest
}

export function update<T extends any[]>(
  array: T,
  index: number,
  newItem: T[number],
): T {
  return [...array.slice(0, index), newItem, ...array.slice(index + 1)] as T
}

export function insert<T>(
  array: T[],
  index: number,
  item: T,
): T[] {
  return [...array.slice(0, index), item, ...array.slice(index)]
}

export function remove<T>(array: T[], index: number): T[] {
  return [...array.slice(0, index), ...array.slice(index + 1)]
}

export function move<T>(array: T[], from: number, to: number): T[] {
  const item = array[from]
  return array.map((x, i) => {
    if (i === from) return array[to]!
    if (i === to) return item
    return x
  })
}

export function swap<T>(array: T[], i: number, j: number): T[] {
  const result = [...array]
  ;[result[i], result[j]] = [result[j]!, result[i]!]
  return result
}

export function pluck<T, K extends keyof T>(
  array: T[],
  key: K,
): T[K][] {
  return array.map(item => item[key])
}

export function where<T>(spec: Partial<Record<keyof T, any>>) {
  return (obj: T): boolean => {
    for (const key in spec) {
      if (obj[key] !== spec[key]) return false
    }
    return true
  }
}

export function whereEq<T>(spec: Partial<T>) {
  return (obj: T): boolean => {
    for (const key in spec) {
      if (obj[key] !== spec[key]) return false
    }
    return true
  }
}

export function propEq<K extends string | number>(
  key: K,
  value: any,
) {
  return (obj: any): boolean => obj[key] === value
}

export function pathEq(path: (string | number)[], value: any) {
  return (obj: any): boolean => {
    let current = obj
    for (const key of path) {
      current = current?.[key]
    }
    return current === value
  }
}

export function propOr<K extends string | number, T>(
  defaultValue: T,
  key: K,
  obj: any,
): T {
  return obj?.[key] ?? defaultValue
}

export function pathOr<T>(defaultValue: T, path: (string | number)[], obj: any): T {
  let current = obj
  for (const key of path) {
    current = current?.[key]
  }
  return current ?? defaultValue
}

export function propSatisfies<T, K extends string | number>(
  pred: (value: any) => boolean,
  key: K,
  obj: any,
): boolean {
  return pred(obj?.[key])
}

export function keys<T extends object>(obj: T): Array<keyof T> {
  return Object.keys(obj) as Array<keyof T>
}

export function values<T extends object>(obj: T): Array<T[keyof T]> {
  return Object.values(obj)
}

export function entries<T extends object>(obj: T): Array<[keyof T, T[keyof T]]> {
  return Object.entries(obj) as Array<[keyof T, T[keyof T]]>
}

export function fromEntries<T extends object>(
  entries: Array<[string, any]>,
): T {
  return Object.fromEntries(entries) as T
}

export function mapObj<T extends object, R>(
  fn: (value: T[keyof T], key: keyof T) => R,
  obj: T,
): Record<keyof T, R> {
  const result = {} as Record<keyof T, R>
  for (const key in obj) {
    result[key] = fn(obj[key], key)
  }
  return result
}

export function filterObj<T extends object>(
  pred: (value: T[keyof T], key: keyof T) => boolean,
  obj: T,
): Partial<T> {
  const result = {} as Partial<T>
  for (const key in obj) {
    if (pred(obj[key], key)) {
      result[key] = obj[key]
    }
  }
  return result
}

export function reduceObj<T extends object, R>(
  fn: (acc: R, value: T[keyof T], key: keyof T) => R,
  initial: R,
  obj: T,
): R {
  let result = initial
  for (const key in obj) {
    result = fn(result, obj[key], key)
  }
  return result
}
